SELECT REVIEW_NO, NO, GROUP_NO, REVIEW_TITLE, IMG_URL, CONTENT, VIEWS,
COMMENTS, STAR,
CATEGORY FROM REVIEW WHERE REVIEW_NO = #{idx}

SELECT GROUP_NO, NO, GROUP_TITLE,TO_CHAR(START_DATE, 'yyyy-MM-dd
HH24:MI') AS START_DATE,TO_CHAR(LAST_DATE, 'yyyy-MM-dd HH24:MI') AS
LAST_DATE, PRICE FROM GROUP_MORAK WHERE GROUP_NO = #{idx}
